#include <bits/stdc++.h>
using namespace std;
typedef string st;
st s;
st fun(int x)
{
    int num=0,i=x,t1=0;
    st t="",ans="";
    while(num!=-1&&i<=s.size()-1)
    {
        if(s[i]>='A'&&s[i]<='Z'&&num==0) t+=s[i];
        else if(s[i]=='[')
        {
            num++;
            if(num==1)
            {
                t+=fun(i+1);
            }
        }
        else if(s[i]==']') num--;
        else if(s[i]>='0'&&s[i]<='9'&&num==0) t1=t1*10+s[i]-'0';
        i++;
    }
    t1=max(t1,1);
    for(int j=0;j<t1;j++)
    {
        ans+=t;
    }
    return ans;
}
int main()
{
    cin>>s;
    cout<<fun(0);
    return 0;
}
